function u(n){if(!n)return"Jamais";const a=new Date(n);if(Number.isNaN(a.getTime()))return"Jamais";const s=Date.now()-a.getTime(),e=Math.floor(s/1e3),t=Math.floor(e/60),o=Math.floor(t/60),r=Math.floor(o/24),i=Math.floor(r/30),f=Math.floor(r/365);return t<1?`Il y a ${e} secondes`:t<2?"Il y a 1 minute":o<1?`Il y a ${t} minutes`:o<24?`Il y a ${o}h ${t%60<10?"0":""}${t%60}m`:r<2?"Il y a 1 jour":r<30?`Il y a ${r} jours`:r<60?"Il y a 1 mois":r<365?`Il y a ${i} mois`:r<730?"Il y a 1 an":`Il y a ${f} ans`}export{u as f};
